import{_ as a,o as s,c as n,a5 as o}from"./chunks/framework.B5tqjWbr.js";const h=JSON.parse('{"title":"概念：UPS 命令响应与拒绝原因（command response and reject reason）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：UPS 命令响应与拒绝原因（command response and reject reason）","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0033-ups-command-response.html` 的源稿和补充资料。它只使用教学响应码，不包含公司内部通信响应码、协议错误码、客户项目参数或未公开产品方案。"},"headers":[],"relativePath":"content/power/concepts/embedded/ups-command-response.md","filePath":"content/power/concepts/embedded/ups-command-response.md","lastUpdated":null}'),p={name:"content/power/concepts/embedded/ups-command-response.md"};function d(l,e,t,i,c,r){return s(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="概念-ups-命令响应与拒绝原因-command-response-and-reject-reason" tabindex="-1">概念：UPS 命令响应与拒绝原因（command response and reject reason） <a class="header-anchor" href="#概念-ups-命令响应与拒绝原因-command-response-and-reject-reason" aria-label="Permalink to &quot;概念：UPS 命令响应与拒绝原因（command response and reject reason）&quot;">​</a></h1><p>本页是 <code>lessons/0033-ups-command-response.html</code> 的源稿和补充资料。它只使用教学响应码，不包含公司内部通信响应码、协议错误码、客户项目参数或未公开产品方案。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>命令响应（command response）是固件处理外部命令后返回给外部工具的结果说明。响应码（response code）说明命令处理结果，例如 <code>OK</code>、<code>ACCEPTED</code>、<code>REJECTED</code>。拒绝原因（reject reason）说明为什么命令没有被执行，例如 <code>NOT_SAFE_TO_CLEAR</code>。</p><p>本课只讲一个概念：命令被拒绝时也要返回可诊断原因，而不是让外部工具猜。</p><h2 id="为什么-ups-需要它" tabindex="-1">为什么 UPS 需要它 <a class="header-anchor" href="#为什么-ups-需要它" aria-label="Permalink to &quot;为什么 UPS 需要它&quot;">​</a></h2><p>上一节讲了命令解析（command parsing）和安全门控（safety gating）。安全门控拒绝清故障请求后，外部工具还需要知道“是通信坏了、命令错了，还是安全条件不满足”。没有响应码，调试人员会把安全拒绝误判成通信故障。</p><p>UPS 中很多命令会影响故障锁存、输出许可或模式切换。响应码能把“命令已看懂”和“动作是否执行”分开表达。</p><h2 id="物理直觉" tabindex="-1">物理直觉 <a class="header-anchor" href="#物理直觉" aria-label="Permalink to &quot;物理直觉&quot;">​</a></h2><p>命令响应像值班工程师给外部工具回话：读状态请求可以说“OK”；不安全的清故障请求要说“拒绝，原因是当前不安全”；安全条件满足后的清故障请求可以说“已接受”。</p><h2 id="数学形式" tabindex="-1">数学形式 <a class="header-anchor" href="#数学形式" aria-label="Permalink to &quot;数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>parsed = parse(raw_command)</span></span>
<span class="line"><span>gated = apply_safety_gate(parsed, safe_to_clear_fault)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>if parsed.type == READ_STATUS:</span></span>
<span class="line"><span>    response_code = OK</span></span>
<span class="line"><span>    reject_reason = NONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>if parsed.type == CLEAR_FAULT_REQUEST and gated.request_clear_fault:</span></span>
<span class="line"><span>    response_code = ACCEPTED</span></span>
<span class="line"><span>    reject_reason = NONE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>if parsed.type == CLEAR_FAULT_REQUEST and not gated.request_clear_fault:</span></span>
<span class="line"><span>    response_code = REJECTED</span></span>
<span class="line"><span>    reject_reason = NOT_SAFE_TO_CLEAR</span></span></code></pre></div><p>本课只建三个教学响应码，不实现真实协议的异常码表。</p><h2 id="仿真观察" tabindex="-1">仿真观察 <a class="header-anchor" href="#仿真观察" aria-label="Permalink to &quot;仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\ups_command_response.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>默认生成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>simulations/results/ups_command_response.png</span></span></code></pre></div><p>图中包含命令类型、响应码和拒绝原因。图内参数框说明：0 ms 读状态返回 <code>OK</code>，20 ms 不安全清故障返回 <code>REJECTED / NOT_SAFE_TO_CLEAR</code>，40 ms 安全清故障返回 <code>ACCEPTED</code>。默认不加 <code>--no-open</code> 时脚本会尝试自动打开图片；打不开时会打印完整路径。</p><h2 id="固件落地" tabindex="-1">固件落地 <a class="header-anchor" href="#固件落地" aria-label="Permalink to &quot;固件落地&quot;">​</a></h2><ul><li><code>UpsCommandResponseCode</code>：教学响应码枚举。</li><li><code>UPS_RESPONSE_OK</code>：读状态这类不改变安全状态的命令处理成功。</li><li><code>UPS_RESPONSE_ACCEPTED</code>：需要执行的命令已被接受。</li><li><code>UPS_RESPONSE_REJECTED</code>：命令被拒绝。</li><li><code>UpsRejectReason</code>：教学拒绝原因枚举。</li><li><code>UPS_REJECT_REASON_NOT_SAFE_TO_CLEAR</code>：当前不满足清故障安全条件。</li><li><code>UpsCommandResponse_FromCommand()</code>：根据原始命令、安全门控后的命令和安全条件生成响应。</li><li><code>UpsCommandResponse_Print()</code>：打印可检查证据。</li></ul><p>真实工程可能还会包含协议校验失败、权限不足、参数越界、忙碌、超时和版本不匹配等响应。本课只训练最小阅读路径。</p><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><ul><li>错误理解：命令被拒绝就不用回复。<br> 正确理解：拒绝也应该尽量说明原因，否则外部工具无法区分安全拒绝和通信故障。</li><li>错误理解：响应码等于故障码。<br> 正确理解：故障码描述设备故障；响应码描述通信命令处理结果。</li><li>错误理解：可以把导师给的真实响应码表记到学习仓库。<br> 正确理解：不能记录公司内部通信响应码，只能记录通用分类方法。</li></ul><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能运行 <code>python simulations\\python\\ups_command_response.py --no-open</code> 并打开 <code>simulations/results/ups_command_response.png</code>。</li><li>能解释响应码和拒绝原因的区别。</li><li>能解释为什么 <code>REJECTED</code> 不是通信失败，而是一个明确处理结果。</li><li>能编译并运行 <code>projects/03-ups-c-firmware-skeleton</code>，看到 <code>command_response</code> 输出。</li><li>能基于 <code>command_response.c -&gt; UpsCommandResponse_FromCommand()</code> 准备导师问题。</li></ul><h2 id="导师问题" tabindex="-1">导师问题 <a class="header-anchor" href="#导师问题" aria-label="Permalink to &quot;导师问题&quot;">​</a></h2><ul><li>我用 <code>command_response.c -&gt; UpsCommandResponse_FromCommand()</code> 区分 <code>OK</code>、<code>ACCEPTED</code> 和 <code>REJECTED</code>。真实工程里通常如何区分“已收到”“已执行”和“拒绝执行”？</li><li>我用 <code>simulations/results/ups_command_response.png</code> 看到不安全清故障返回 <code>NOT_SAFE_TO_CLEAR</code>。真实工程中拒绝原因通常会细分到什么程度？</li><li>我不会记录公司内部通信响应码，只想确认阅读方式：看真实工程时，响应码表、命令解析表和故障码表应该分开看还是合在一起看？</li></ul>`,28)])])}const _=a(p,[["render",d]]);export{h as __pageData,_ as default};
